//! `smj workspace` — init, indexing, path registration, and agent routing.

use std::path::Path;

use anyhow::{Context as _, Result};
use clap::Subcommand;
use serde_json::json;
use smedja_rpc::client::Client;

use crate::util::connect;

const AGENTS_TOML_TEMPLATE: &str = r#"# .smedja/agents.toml — workspace agent configuration
# Generated by `smj workspace agents init`
# See docs/configuration.md for the full field reference.

[roles.impl]
runner = "local"
tier   = "local"
model  = "Qwen3-14B"
tools  = ["read_file", "edit_file", "bash"]

[roles.review]
runner = "claude"
tier   = "deep"
tools  = ["read_file", "graph_query"]

[roles.test]
runner = "local"
tier   = "local"
tools  = ["read_file", "bash"]
"#;

#[derive(Subcommand)]
pub(crate) enum WorkspaceCmd {
    /// Agent management
    Agents {
        #[command(subcommand)]
        action: AgentsCmd,
    },
    /// Initialise a workspace: create .smedja/, index symbols, and write workspace.toml
    Init {
        /// Directory to initialise (defaults to current directory)
        path: Option<std::path::PathBuf>,
    },
    /// Index the current workspace into the code graph
    Index {
        /// Optional git commit SHA for incremental re-indexing
        #[arg(long)]
        commit_sha: Option<String>,
    },
    /// Register a directory path with the workspace
    Add {
        /// Directory path to add to the workspace
        path: String,
    },
}

#[derive(Subcommand)]
pub(crate) enum AgentsCmd {
    /// Print the resolved role→runner→tier→model table for the current workspace
    Show,
    /// Generate a starter .smedja/agents.toml in the current directory
    Init,
}

/// Dispatches a `smj workspace` subcommand.
pub(crate) async fn run(sock: &Path, action: WorkspaceCmd) -> Result<()> {
    match action {
        WorkspaceCmd::Agents {
            action: agents_action,
        } => match agents_action {
            AgentsCmd::Show => {
                let mut client = connect(sock).await?;
                cmd_workspace_agents(&mut client).await?;
            }
            AgentsCmd::Init => {
                let target = Path::new(".smedja");
                std::fs::create_dir_all(target)?;
                let agents_toml = target.join("agents.toml");
                if agents_toml.exists() {
                    anyhow::bail!(".smedja/agents.toml already exists");
                }
                std::fs::write(&agents_toml, AGENTS_TOML_TEMPLATE)?;
                println!("Created {}", agents_toml.display());
            }
        },
        WorkspaceCmd::Init { path } => {
            let target = path.unwrap_or_else(|| std::env::current_dir().expect("cwd"));
            if !target.exists() {
                anyhow::bail!("path does not exist: {}", target.display());
            }
            let mut client = connect(sock).await?;
            let resp = client
                .call(
                    "graph.index",
                    json!({ "workspace": target.display().to_string() }),
                )
                .await
                .context("graph.index failed")?;
            let count = resp["indexed"].as_u64().unwrap_or(0);
            println!("Indexed {count} symbols in {}", target.display());
            cmd_workspace_init(&target)?;
        }
        WorkspaceCmd::Index { commit_sha } => {
            // `commit_sha` is accepted for CLI compatibility; the server-side
            // index performs a full re-index.
            let _ = commit_sha;
            let workspace =
                std::env::current_dir().context("cannot determine current directory")?;
            let mut client = connect(sock).await?;
            let resp = client
                .call(
                    "graph.index",
                    json!({ "workspace": workspace.display().to_string() }),
                )
                .await
                .context("graph.index failed")?;
            let count = resp["indexed"].as_u64().unwrap_or(0);
            println!("Indexed {count} symbols in {}", workspace.display());
        }
        WorkspaceCmd::Add { path } => {
            let workspace =
                std::env::current_dir().context("cannot determine current directory")?;
            let smedja_dir = workspace.join(".smedja");
            std::fs::create_dir_all(&smedja_dir)?;
            let toml_path = smedja_dir.join("workspace.toml");

            // Read existing content or start fresh.
            let mut content = if toml_path.exists() {
                std::fs::read_to_string(&toml_path).context("failed to read workspace.toml")?
            } else {
                String::new()
            };

            // Append the new path entry.
            if !content.is_empty() && !content.ends_with('\n') {
                content.push('\n');
            }
            content.push_str("\n[[workspace.paths]]\npath = \"");
            content.push_str(&path);
            content.push_str("\"\n");
            std::fs::write(&toml_path, &content).context("failed to write workspace.toml")?;
            println!("Added path '{}' to {}", path, toml_path.display());
        }
    }
    Ok(())
}

/// Prints the resolved role→runner→tier→model routing table for the current
/// workspace, sourcing each decision from the daemon's `agent.routing` RPC.
///
/// The printed format is identical to the previous in-process implementation so
/// downstream tooling and operators see no change.
async fn cmd_workspace_agents(client: &mut Client) -> Result<()> {
    println!("{:<15} {:<10} {:<8} MODEL", "ROLE", "RUNNER", "TIER");
    println!("{}", "-".repeat(55));

    for role_name in &["orchestrator", "impl", "test", "review", "sre"] {
        let resp = client
            .call(
                "agent.routing",
                json!({ "role": role_name, "complexity": "coding" }),
            )
            .await
            .context("agent.routing failed")?;
        let runner = resp["runner"].as_str().unwrap_or("-");
        let tier = resp["tier"].as_str().unwrap_or("-");
        let model = resp["model"].as_str().unwrap_or("-");
        println!("{role_name:<15} {runner:<10} {tier:<8} {model}");
    }
    Ok(())
}

/// Initialises a smedja workspace at the given directory.
///
/// Creates `.smedja/` and writes a `workspace.toml` with `auto_index = true`
/// and the current timestamp. Symbol indexing is performed separately via the
/// daemon's `graph.index` RPC by the caller.
fn cmd_workspace_init(dir: &Path) -> Result<()> {
    use chrono::Utc;
    let smedja_dir = dir.join(".smedja");
    std::fs::create_dir_all(&smedja_dir)?;
    let toml_path = smedja_dir.join("workspace.toml");
    let ts = Utc::now().to_rfc3339();
    let content = format!("[graph]\nauto_index = true\nlast_indexed_at = \"{ts}\"\n");
    std::fs::write(&toml_path, content)?;
    println!("Initialized workspace at {}", dir.display());
    Ok(())
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn workspace_init_creates_dir_and_toml() {
        let dir = tempfile::tempdir().unwrap();
        cmd_workspace_init(dir.path()).unwrap();
        assert!(dir.path().join(".smedja").exists());
        let toml_content =
            std::fs::read_to_string(dir.path().join(".smedja").join("workspace.toml")).unwrap();
        assert!(toml_content.contains("auto_index = true"));
        assert!(toml_content.contains("last_indexed_at"));
    }

    #[test]
    fn auto_index_fires_when_stale() {
        let dir = tempfile::tempdir().unwrap();
        let smedja_dir = dir.path().join(".smedja");
        std::fs::create_dir_all(&smedja_dir).unwrap();
        let old_ts = (chrono::Utc::now() - chrono::Duration::hours(25)).to_rfc3339();
        let content = format!("[graph]\nauto_index = true\nlast_indexed_at = \"{old_ts}\"\n");
        std::fs::write(smedja_dir.join("workspace.toml"), &content).unwrap();
        // Verify the staleness-check logic matches what smdjad does at session.create.
        let parsed: toml::Value = toml::from_str(&content).unwrap();
        let ts_str = parsed["graph"]["last_indexed_at"].as_str().unwrap();
        let ts = chrono::DateTime::parse_from_rfc3339(ts_str).unwrap();
        let age = chrono::Utc::now().signed_duration_since(ts.with_timezone(&chrono::Utc));
        assert!(age.num_hours() >= 24, "25h old timestamp must be stale");
    }
}
